import { tags } from 'decantr/tags';
import { createSignal } from 'decantr/state';
import { css } from 'decantr/css';
import { Button, icon, Badge, Input, Select } from 'decantr/components';

code.example:
function PaymentHistory({ payments }) {
  const { div, h1, span, table, thead, tbody, tr, th, td } = tags;
  const [dateFrom, setDateFrom] = createSignal('');
  const [dateTo, setDateTo] = createSignal('');
  const [typeFilter, setTypeFilter] = createSignal('all');
  const [statusFilter, setStatusFilter] = createSignal('all');

  const filtered = () => payments.filter(p => {
    if (typeFilter() !== 'all' && p.type !== typeFilter()) return false;
    if (statusFilter() !== 'all' && p.status !== statusFilter()) return false;
    if (dateFrom() && new Date(p.date) < new Date(dateFrom())) return false;
    if (dateTo() && new Date(p.date) > new Date(dateTo())) return false;
    return true;
  });

  const total = filtered().filter(p => p.status === 'completed').reduce((sum, p) => sum + p.amount, 0);

  return div({ class: css('_flex _col _gap6') },
    div({ class: css('_flex _jcsb _aic') },
      h1({ class: css('_heading3') }, 'Payment History'),
      Button({ variant: 'outline' }, icon('download'), 'Export CSV')
    ),
    div({ class: css('_flex _gap4 _aic _flexwrap') },
      div({ class: css('_flex _gap2 _aic') },
        span({ class: css('_textsm _fgmuted') }, 'From'),
        Input({ type: 'date', value: dateFrom(), oninput: e => setDateFrom(e.target.value) }),
        span({ class: css('_textsm _fgmuted') }, 'To'),
        Input({ type: 'date', value: dateTo(), oninput: e => setDateTo(e.target.value) })
      ),
      Select({ value: typeFilter(), onchange: e => setTypeFilter(e.target.value) },
        tags.option({ value: 'all' }, 'All Types'),
        tags.option({ value: 'rent' }, 'Rent'),
        tags.option({ value: 'deposit' }, 'Deposit'),
        tags.option({ value: 'fee' }, 'Fee'),
        tags.option({ value: 'other' }, 'Other')
      ),
      Select({ value: statusFilter(), onchange: e => setStatusFilter(e.target.value) },
        tags.option({ value: 'all' }, 'All Status'),
        tags.option({ value: 'completed' }, 'Completed'),
        tags.option({ value: 'pending' }, 'Pending'),
        tags.option({ value: 'failed' }, 'Failed'),
        tags.option({ value: 'refunded' }, 'Refunded')
      ),
      span({ class: css('_ml[auto] _font500') }, `Total: $${total.toLocaleString()}`)
    ),
    div({ class: css('estate-table _overflow[auto]') },
      table({ class: css('_wfull') },
        thead({},
          tr({ class: css('_bgSurface') },
            th({ class: css('_p3 _textleft _font500') }, 'Date'),
            th({ class: css('_p3 _textleft _font500') }, 'Tenant'),
            th({ class: css('_p3 _textleft _font500') }, 'Property / Unit'),
            th({ class: css('_p3 _tc _font500') }, 'Type'),
            th({ class: css('_p3 _tr _font500') }, 'Amount'),
            th({ class: css('_p3 _textleft _font500') }, 'Method'),
            th({ class: css('_p3 _tc _font500') }, 'Status'),
            th({ class: css('_p3') })
          )
        ),
        tbody({},
          ...filtered().map((p, i) => {
            const statusColor = p.status === 'completed' ? 'success' : p.status === 'pending' ? 'warning' : p.status === 'failed' ? 'danger' : 'default';
            return tr({ class: css(i % 2 === 0 ? '' : '_bgSurfaceRaised') },
              td({ class: css('_p3 _textsm') }, new Date(p.date).toLocaleDateString()),
              td({ class: css('_p3 _font500') }, p.tenantName),
              td({ class: css('_p3 _textsm') }, `${p.propertyName} - Unit ${p.unitNumber}`),
              td({ class: css('_p3 _tc') }, Badge({ variant: 'outline' }, p.type)),
              td({ class: css('_p3 _tr _font500') }, `$${p.amount.toLocaleString()}`),
              td({ class: css('_p3 _textsm') }, p.method),
              td({ class: css('_p3 _tc') }, Badge({ variant: statusColor }, p.status)),
              td({ class: css('_p3') },
                p.status === 'completed' ? Button({ variant: 'ghost', size: 'sm' }, icon('file-text', { size: '14' })) : null
              )
            );
          })
        )
      )
    )
  );
}

